                    {"type": "category-sort", "categories": ["Базовые анимации", "Продвинутые техники"], "items": [{"text": "Fade In / Fade Out", "category": "Базовые анимации"}, {"text": "Slide In", "category": "Базовые анимации"}, {"text": "Stagger (задержка строк)", "category": "Продвинутые техники"}, {"text": "Анимация Tracking", "category": "Продвинутые техники"}, {"text": "Scale Pop", "category": "Базовые анимации"}, {"text": "Комбинация Slide + Fade + Scale", "category": "Продвинутые техники"}]},
